// Función para formatear contenido manteniendo saltos de línea
function formatContent(content) {
  if (!content) return '<p class=MsoNormal>Contenido pendiente de completar.</p>';
  const lines = content.split('\n');
  let formatted = '';
  lines.forEach(line => {
    const trimmedLine = line.trim();
    if (trimmedLine === '') {
      formatted += '<p class=MsoNormal>&nbsp;</p>';
    } else {
      // Preservar el formato de listas simples
      if (/^\d+\./.test(trimmedLine) || /^[a-zA-Z]\./.test(trimmedLine)) {
        formatted += `<p class=MsoNormal style="margin-left:20.0pt;">${trimmedLine}</p>`;
      } else {
        formatted += `<p class=MsoNormal>${trimmedLine}</p>`;
      }
    }
  });
  return formatted;
}

// Función especial para formatear la normativa con números romanos
function formatNormativa(content) {
  if (!content) return '<p class=MsoNormal>Contenido pendiente de completar.</p>';
  const lines = content.split('\n');
  let formatted = '';
  let inRomanList = false;
  let inDecimalList = false;
  let inAlphaList = false;
  lines.forEach(line => {
    const trimmedLine = line.trim();
    if (trimmedLine === '') {
      if (inAlphaList) {
        formatted += '</ol>';
        inAlphaList = false;
      }
      if (inDecimalList) {
        formatted += '</ol>';
        inDecimalList = false;
      }
      if (inRomanList) {
        formatted += '</ol>';
        inRomanList = false;
      }
      formatted += '<p class=MsoNormal>&nbsp;</p>';
      return;
    }

    // Detectar listas con números romanos (I., II., etc.)
    if (/^[IVX]+\./.test(trimmedLine)) {
      if (!inRomanList) {
        formatted += '<ol class=normativa-roman>';
        inRomanList = true;
      }
      const text = trimmedLine.replace(/^[IVX]+\.\s*/, '');
      formatted += `<li class=MsoNormal>${text}</li>`;
    }
    // Detectar listas decimales (1), 2), etc.)
    else if (/^\d+\)/.test(trimmedLine)) {
      if (inRomanList) {
        formatted += '</ol>';
        inRomanList = false;
      }
      if (!inDecimalList) {
        formatted += '<ol class=normativa-decimal>';
        inDecimalList = true;
      }
      const text = trimmedLine.replace(/^\d+\)\s*/, '');
      formatted += `<li class=MsoNormal>${text}</li>`;
    }
    // Detectar listas alfabéticas (a., b., etc.)
    else if (/^[a-f]\./.test(trimmedLine)) {
      if (inDecimalList) {
        if (!inAlphaList) {
          formatted += '<ol class=normativa-alpha>';
          inAlphaList = true;
        }
        const text = trimmedLine.replace(/^[a-f]\.\s*/, '');
        formatted += `<li class=MsoNormal>${text}</li>`;
      } else {
        formatted += `<p class=MsoNormal>${trimmedLine}</p>`;
      }
    }
    // Texto con subrayado entre corchetes
    else if (trimmedLine.includes('[') && trimmedLine.includes(']')) {
      const underlined = trimmedLine.replace(/\[(.*?)\]/g, '<span class=underline>$1</span>');
      formatted += `<p class=MsoNormal>${underlined}</p>`;
    }
    // Texto normal
    else {
      // Cerrar listas si estamos saliendo de ellas
      if (inAlphaList) {
        formatted += '</ol>';
        inAlphaList = false;
      }
      if (inDecimalList) {
        formatted += '</ol>';
        inDecimalList = false;
      }
      if (inRomanList) {
        formatted += '</ol>';
        inRomanList = false;
      }
      formatted += `<p class=MsoNormal>${trimmedLine}</p>`;
    }
  });

  // Cerrar cualquier lista que quede abierta
  if (inAlphaList) formatted += '</ol>';
  if (inDecimalList) formatted += '</ol>';
  if (inRomanList) formatted += '</ol>';
  return formatted;
}

// Función para generar la tabla de procedimiento
function generateProcedureTable(procedureData) {
  if (!procedureData || procedureData.length === 0) {
    return '<p class=MsoNormal>Contenido pendiente de completar.</p>';
  }
  let tableHTML = `
<table class=procedure-table border=0 cellspacing=0 cellpadding=0 width="100%">
 <tr>
  <th width="15%">(#)</th>
  <th width="25%">(Quien)</th>
  <th width="60%">(Actividad)</th>
 </tr>`;
  procedureData.forEach(row => {
    let number = row.number || '';
    const who = row.who || '';
    const activity = row.activity || '';

    // Convertir numeración a formato 5.x
    if (number && !isNaN(number)) {
      number = `5.${number}`;
    }

    // Determinar la clase de la fila
    let rowClass = '';
    if (!row.number && !row.who && row.activity && !activity.startsWith('¿') && !activity.toLowerCase().startsWith('si') && !activity.toLowerCase().startsWith('no') && activity !== 'Fin del Proceso') {
      rowClass = 'section-row';
    } else if (row.number && !row.who && row.activity) {
      rowClass = 'subsection-row';
    }

    // Si es una fila de sección (solo tiene actividad y las otras están vacías)
    if (!row.number && !row.who && row.activity && !activity.startsWith('¿') && !activity.toLowerCase().startsWith('si') && !activity.toLowerCase().startsWith('no') && activity !== 'Fin del Proceso') {
      tableHTML += `
 <tr class=${rowClass}>
  <td colspan=3><b>${activity}</b></td>
 </tr>`;
    }
    // Si es una fila de subsección (solo tiene número y actividad)
    else if (row.number && !row.who && row.activity) {
      tableHTML += `
 <tr class=${rowClass}>
  <td><b>${number}</b></td>
  <td></td>
  <td><b>${activity}</b></td>
 </tr>`;
    }
    // Si es una pregunta o alternativa (sin número ni responsable)
    else if (!row.number && !row.who && row.activity && (activity.startsWith('¿') || activity.toLowerCase().startsWith('si') || activity.toLowerCase().startsWith('no') || activity === 'Fin del Proceso')) {
      tableHTML += `
 <tr>
  <td></td>
  <td></td>
  <td>${activity}</td>
 </tr>`;
    }
    // Si es una fila normal con todas las columnas
    else if (number || who || activity) {
      tableHTML += `
 <tr class=${rowClass}>
  <td>${number}</td>
  <td>${who}</td>
  <td>${activity}</td>
 </tr>`;
    }
    // Fila vacía para separación
    else {
      tableHTML += `
 <tr>
  <td>&nbsp;</td>
  <td>&nbsp;</td>
  <td>&nbsp;</td>
 </tr>`;
    }
  });
  tableHTML += `
</table>`;
  return tableHTML;
}

